export class UserService {
  async login(email: string, password: string) {
    const user = await this.findByEmail(email);
    if (!user || !this.verifyPassword(password, user.hash)) throw new Error('Invalid credentials');
    return this.generateToken(user);
  }
  private generateToken(user: User): string { /* ... */ return 'token'; }
  private verifyPassword(plain: string, hash: string): boolean { return plain === hash; }
  private async findByEmail(email: string): Promise<User | null> { return null; }
}
